cadishfile:
example.com {
    @strip   cookie StripMe yes
    @forward cookie KeepMe yes
    classify {axis} {
        derives_from cookie StripMe
        derives_from cookie KeepMe forward
        when @strip   -> 1
        when @forward -> 2
        default       -> 0
    }
    cookie_allow
    cache_key default host url {axis}
    cache_ttl default ttl 60s
    header +cache_status X-Cache
}
